import psycopg2
from psycopg2 import sql
import sys

def connect_to_database(host, port, database, user, password):
    try:
        connection = psycopg2.connect(
            host=host,
            port=port,
            database=database,
            user=user,
            password=password
        )
        return connection
    except psycopg2.Error as e:
        print(f"Error connecting to PostgreSQL: {e}")
        sys.exit(1)

def install_extension(connection, extension_name):
    try:
        cursor = connection.cursor()
        
        # Validate extension name to prevent SQL injection
        if not extension_name.replace('_', '').replace('-', '').isalnum():
            raise ValueError("Invalid extension name")
        
        # Use sql.Identifier for safe identifier handling
        safe_extension_name = sql.Identifier(extension_name)
        
        # Check if extension already exists
        check_query = """
        SELECT 1 FROM pg_extension WHERE extname = %s;
        """
        cursor.execute(check_query, (extension_name,))
        
        if cursor.fetchone():
            print(f"Extension '{extension_name}' already exists.")
            return False
        
        # Create extension
        create_query = sql.SQL("CREATE EXTENSION IF NOT EXISTS {}").format(safe_extension_name)
        cursor.execute(create_query)
        
        connection.commit()
        print(f"Extension '{extension_name}' installed successfully.")
        return True
        
    except psycopg2.Error as e:
        print(f"Error installing extension: {e}")
        connection.rollback()
        return False
    except ValueError as e:
        print(f"Validation error: {e}")
        return False
    finally:
        if cursor:
            cursor.close()

def main():
    # Database connection parameters
    db_config = {
        'host': 'localhost',
        'port': 5432,
        'database': 'your_database',
        'user': 'your_username',
        'password': 'your_password'
    }
    
    # Connect to database
    connection = connect_to_database(**db_config)
    
    try:
        # Get extension names from user input
        extensions_input = input("Enter extension names (comma-separated): ")
        extension_names = [ext.strip() for ext in extensions_input.split(',') if ext.strip()]
        
        if not extension_names:
            print("No extensions provided.")
            return
        
        # Install each extension
        for extension_name in extension_names:
            install_extension(connection, extension_name)
            
    finally:
        connection.close()

if __name__ == "__main__":
    main()